const dashboard = $('Get Dashboard Stats').first().json;
const topProducts = $('Get Top Products').first().json;

const s = dashboard.data || dashboard;
const products = ((topProducts.data && topProducts.data.products) || topProducts.products || []).slice(0, 5);

const topList = products.length > 0
  ? products.map((p, i) => `  ${i+1}. ${p.name || p.product_name} - ${p.revenue || p.total_revenue || 0}`).join('\n')
  : '  No sales yet';

const msg = `\u{1F4CA} *Sellf Daily Report*\n` +
  `\u{1F4C5} ${new Date().toISOString().split('T')[0]}\n\n` +
  `\u{1F4B0} Revenue today: *${(s.revenue && s.revenue.today) || 0}*\n` +
  `\u{1F6D2} Orders today: *${(s.transactions && s.transactions.today) || 0}*\n` +
  `\u{1F465} Users with access: *${(s.users && s.users.with_access) || 0}*\n` +
  `\u{1F4E6} Active products: *${(s.products && s.products.active) || 0}*\n` +
  `\u21A9\uFE0F Pending refunds: *${(s.refunds && s.refunds.pending_count) || 0}*\n\n` +
  `\u{1F3C6} *Top products (today):*\n${topList}`;

return [{ json: { message: msg } }];
